// SPDX-License-Identifier: GPL-3.0-only
pragma solidity >=0.8.3;

/// @dev The Ed25519Verifier precompile address
address constant ED25519_VERIFIER_ADDRESS = 0x00000000000000000000000000000000000013bA;

Ed25519Verifier constant ED25519_VERIFIER_CONTRACT = Ed25519Verifier(ED25519_VERIFIER_ADDRESS);

/// @title Ed25519Verifier interface
/// @notice This interface defines the function for verifying ed25519 signatures.
interface Ed25519Verifier {
    /// @dev Verifies an ed25519 signature.
    /// @param message The message that was signed.
    /// @param signature The 64-byte ed25519 signature.
    /// @param publicKey The 32-byte ed25519 public key.
    /// @return bool true if the signature is valid, false otherwise.
    function verify(bytes calldata message, bytes calldata signature, bytes32 publicKey) external view returns (bool);
}

// SPDX-License-Identifier: GPL-3.0-only
pragma solidity >=0.8.3;

/// @dev The Sr25519Verifier precompile address
address constant SR25519_VERIFIER_ADDRESS = 0x00000000000000000000000000000000000013B9;

Sr25519Verifier constant SR25519_VERIFIER_CONTRACT = Sr25519Verifier(SR25519_VERIFIER_ADDRESS);

/// @title Sr25519Verifier interface
/// @notice This interface defines the function for verifying Substrate sr25519 signatures.
interface Sr25519Verifier {
    /// @dev Verifies an sr25519 signature.
    /// @param message The message that was signed.
    /// @param signature The 64-byte sr25519 signature.
    /// @param publicKey The 32-byte sr25519 public key.
    /// @return bool true if the signature is valid, false otherwise.
    function verify(bytes calldata message, bytes calldata signature, bytes32 publicKey) external view returns (bool);
}

// SPDX-License-Identifier: GPL-3.0-only
pragma solidity >=0.8.3;

/// @dev The Deposit precompile address
address constant SUBSTRATE_TRANSFER_ADDRESS = 0x0000000000000000000000000000000000000Fd1;

SubstrateTransfer constant SUBSTRATE_TRANSFER_ADRRESS = SubstrateTransfer(SUBSTRATE_TRANSFER_ADDRESS);

/// @title SubstrateTransfer interface
interface SubstrateTransfer {
    /// @dev Event emitted when a transfer has been performed.
    /// @param from Address which tokens are sent from.
    /// @param destination The Substrate address receiving the tokens.
    /// @param amount The amount of tokens transferred.
    event Transfer(address indexed from, bytes32 indexed destination, uint256 amount);

    /// @dev Function to transfer tokens to a Substrate address.
    /// @param destination The Substrate address receiving the tokens.
    /// @param amount The amount of tokens to transfer.
    function transfer_substrate(bytes32 destination, uint256 amount) external;
}
